// SPDX-License-Identifier: Apache-2.0 WITH LLVM-exception
#include "llvm/Pass.h"
#include "llvm/IR/IRBuilder.h"
#include "llvm/IR/Instructions.h"
#include "llvm/Support/async.h"
#include "llvm/InitializePasses.h"

using namespace llvm;

namespace {

class OverflowCheckPass : public PassInfoMixin<OverflowCheckPass> {
public:
  // Async entry point that schedules the actual work.
  PreservedAnalyses run(Module &M, ModuleAnalysisManager &) {
    // Co‑await the scheduler to allow concurrent passes.
    co_await llvm::async::SchedulePass([&]() {
      return runOnModuleImpl(M);
    });
    return PreservedAnalyses::all();
  }

private:
  // Synchronous implementation containing the transformed logic.
  PreservedAnalyses runOnModuleImpl(Module &M) {
    LLVMContext &Ctx = M.getContext();
    IRBuilder<> Builder(Ctx);

    // Compile‑time mask for fast‑path test.
    constexpr uint64_t OverflowDetectionMaskConstant = 0xFFFFFFFF00000000ULL;

    for (Function &F : M) {
      for (BasicBlock &BB : F) {
        for (Instruction &I : BB) {
          if (auto *BinOp = dyn_cast<BinaryOperator>(&I)) {
            if (BinOp->getOpcode() != Instruction::Add) continue;

            Value *LHS = BinOp->getOperand(0);
            Value *RHS = BinOp->getOperand(1);

            // Compute sum for fast‑path test.
            Value *Sum = Builder.CreateAdd(LHS, RHS, "add.tmp");

            // Bitwise AND with mask to isolate high bits.
            Value *HighBits = Builder.CreateAnd(
                Sum,
                ConstantInt::get(Ctx, APInt(64, OverflowDetectionMaskConstant)),
                "high.bits");

            // Fast‑path: if high bits are zero, no overflow.
            Value *IsSafe = Builder.CreateICmpEQ(
                HighBits,
                ConstantInt::get(Ctx, APInt(64, 0)),
                "overflow.safe");

            // Ternary selection: safe path uses Sum, slow path calls intrinsic.
            Value *Result = Builder.CreateSelect(
                IsSafe,
                Sum,
                Builder.CreateCall(
                    Intrinsic::getDeclaration(
                        &M,
                        Intrinsic::sadd_with_overflow,
                        {LHS->getType()}),
                    {LHS, RHS},
                    "overflow.call"));

            // Replace original addition with the selected result.
            BinOp->replaceAllUsesWith(Result);
            BinOp->eraseFromParent();
          }
        }
      }
    }
    return PreservedAnalyses::all();
  }
};

} // end anonymous namespace

